"use client";

import { useEffect, useRef } from "react";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";

gsap.registerPlugin(ScrollTrigger);

const SKILLS = [
  "Python",
  "NumPy",
  "Pandas",
  "Scikit-learn",
  "Generative AI",
  "NLP",
  "RAG",
  "API Integration",
  "TypeScript",
  "JavaScript",
  "CSS",
  "Git",
];

export default function About() {
  const sectionRef = useRef<HTMLElement>(null);
  const textRef = useRef<HTMLParagraphElement>(null);
  const skillsRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const text = textRef.current;
    const skills = skillsRef.current;
    const section = sectionRef.current;
    if (!text || !skills || !section) return;

    // Split paragraph into words for scroll reveal
    const rawText = text.textContent || "";
    text.innerHTML = "";
    const words: HTMLSpanElement[] = [];
    rawText.split(" ").forEach((word, i) => {
      const span = document.createElement("span");
      span.className = "split-word inline-block mr-[0.3em]";
      span.textContent = word;
      span.style.opacity = "0.15";
      span.style.transform = "translateY(10px)";
      text.appendChild(span);
      words.push(span);
    });

    gsap.to(words, {
      opacity: 1,
      y: 0,
      duration: 0.6,
      ease: "power3.out",
      stagger: 0.02,
      scrollTrigger: {
        trigger: section,
        start: "top 70%",
        end: "center 50%",
        scrub: 1,
      },
    });

    // Animate skills grid
    const skillTags = skills.querySelectorAll(".skill-tag");
    gsap.fromTo(
      skillTags,
      { opacity: 0, y: 20, scale: 0.9 },
      {
        opacity: 1,
        y: 0,
        scale: 1,
        duration: 0.5,
        ease: "power3.out",
        stagger: 0.04,
        scrollTrigger: {
          trigger: skills,
          start: "top 80%",
          toggleActions: "play none none none",
        },
      }
    );

    return () => {
      ScrollTrigger.getAll().forEach((st) => st.kill());
    };
  }, []);

  return (
    <section
      ref={sectionRef}
      id="about"
      className="relative py-section px-6 md:px-12"
    >
      <div className="max-w-[1400px] mx-auto">
        {/* Section label */}
        <div className="flex items-center gap-4 mb-12 md:mb-16">
          <span className="text-electric-blue text-sm font-medium tracking-[0.2em] uppercase">
            About
          </span>
          <div className="h-[1px] w-16 bg-electric-blue/30" />
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-[1.5fr_1fr] gap-12 lg:gap-20">
          {/* Text column */}
          <div>
            <p
              ref={textRef}
              className="text-[clamp(1.1rem,2.5vw,1.75rem)] font-medium leading-[1.6] text-text-primary"
            >
              I am a B.Tech undergraduate in Artificial Intelligence and Data
              Science (2023ΓÇô2027), focused on building practical AI-powered
              applications. While I am currently learning Machine Learning
              fundamentals, I have hands-on experience with Generative AI, NLP,
              and real-world AI integrations through projects.
            </p>
          </div>

          {/* Skills column */}
          <div>
            <h3 className="text-sm font-medium text-text-muted uppercase tracking-[0.15em] mb-6">
              Skills & Technologies
            </h3>
            <div ref={skillsRef} className="flex flex-wrap gap-2">
              {SKILLS.map((skill) => (
                <span key={skill} className="skill-tag">
                  {skill}
                </span>
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
